import{_ as e,o as i,c as o,ae as r}from"./chunks/framework.CyZiF_rV.js";const z=JSON.parse('{"title":"Weryfikacja faktury","description":"","frontmatter":{},"headers":[],"relativePath":"pl/faktury/weryfikacja-faktury.md","filePath":"pl/faktury/weryfikacja-faktury.md"}'),n={name:"pl/faktury/weryfikacja-faktury.md"};function t(l,a,d,c,y,u){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="weryfikacja-faktury" tabindex="-1">Weryfikacja faktury <a class="header-anchor" href="#weryfikacja-faktury" aria-label="Permalink to &quot;Weryfikacja faktury&quot;">​</a></h1><p>15.01.2026</p><p>Faktura przesyłana do systemu KSeF podlega szeregowi kontroli technicznych i semantycznych. Weryfikacja obejmuje następujące kryteria:</p><h2 id="zgodnosc-ze-schematem-xsd" tabindex="-1">Zgodność ze schematem XSD <a class="header-anchor" href="#zgodnosc-ze-schematem-xsd" aria-label="Permalink to &quot;Zgodność ze schematem XSD&quot;">​</a></h2><p>Faktura musi być przygotowana w formacie XML, kodowana w UTF-8 bez znaku BOM (3 pierwsze bajty 0xEF 0xBB 0xBF), zgodna z zadeklarowanym schematem podanym przy otwarciu sesji.</p><h2 id="unikalnosc-faktury" tabindex="-1">Unikalność faktury <a class="header-anchor" href="#unikalnosc-faktury" aria-label="Permalink to &quot;Unikalność faktury&quot;">​</a></h2><ul><li>KSeF wykrywa duplikaty faktur globalnie, w oparciu o dane przechowywane w systemie. Kryterium identyfikacji duplikatu stanowi kombinacja: <ol><li>NIP sprzedawcy (<code>Podmiot1:NIP</code>)</li><li>Rodzaj faktury (<code>RodzajFaktury</code>)</li><li>Numer faktury (<code>P_2</code>)</li></ol></li><li>W przypadku duplikatu zwracany jest kod błędu 440 („Duplikat faktury”).</li><li>Unikalność faktury utrzymywana jest w KSeF przez okres 10 pełnych lat, liczonych od końca roku kalendarzowego, w którym faktura została wystawiona.</li><li>Kryterium unikalności odnosi się zawsze do sprzedawcy (Podmiot1:NIP). W przypadku, gdy w imieniu tego samego podmiotu faktury wystawiają różne jednostki (np. oddziały, jednostki organizacyjne JST, inne uprawnione podmioty), muszą one uzgodnić zasady numeracji, aby uniknąć duplikatów.</li></ul><h2 id="walidacja-dat" tabindex="-1">Walidacja dat <a class="header-anchor" href="#walidacja-dat" aria-label="Permalink to &quot;Walidacja dat&quot;">​</a></h2><p>Data wystawienia faktury (<code>P_1</code>) nie może być późniejsza niż data przyjęcia dokumentu do systemu KSeF.</p><h2 id="walidacja-numeru-nip" tabindex="-1">Walidacja numeru NIP <a class="header-anchor" href="#walidacja-numeru-nip" aria-label="Permalink to &quot;Walidacja numeru NIP&quot;">​</a></h2><ul><li>Sprawdzenie sumy kontrolnej NIP dla: <code>Podmiot1</code>, <code>Podmiot2</code>, <code>Podmiot3</code> oraz <code>PodmiotUpowazniony</code> (jeśli występuje).</li><li>Dotyczy tylko środowiska produkcyjnego.</li></ul><h2 id="walidacja-numeru-nip-w-identyfikatorze-wewnetrznym" tabindex="-1">Walidacja numeru NIP w identyfikatorze wewnętrznym <a class="header-anchor" href="#walidacja-numeru-nip-w-identyfikatorze-wewnetrznym" aria-label="Permalink to &quot;Walidacja numeru NIP w identyfikatorze wewnętrznym&quot;">​</a></h2><ul><li>Sprawdzenie sumy kontrolnej NIP w identyfikatorze wewnętrznym (<code>InternalId</code>) dla <code>Podmiot3</code> - o ile ten identyfikator występuje.</li><li>Dotyczy tylko środowiska produkcyjnego.</li></ul><h2 id="rozmiar-pliku" tabindex="-1">Rozmiar pliku <a class="header-anchor" href="#rozmiar-pliku" aria-label="Permalink to &quot;Rozmiar pliku&quot;">​</a></h2><ul><li>Maksymalny rozmiar faktury bez załączników: <strong>1 MB *</strong> (1 000 000 bajtów).</li><li>Maksymalny rozmiar faktury z załącznikami: <strong>3 MB *</strong> (3 000 000 bajtów).</li></ul><h2 id="ograniczenia-ilosciowe" tabindex="-1">Ograniczenia ilościowe <a class="header-anchor" href="#ograniczenia-ilosciowe" aria-label="Permalink to &quot;Ograniczenia ilościowe&quot;">​</a></h2><ul><li>Maksymalna liczba faktur w jednej sesji (zarówno interaktywnej, jak i wsadowej) wynosi 10 000 *.</li><li>W ramach wysyłki wsadowej można przesłać maksymalnie 50 plików ZIP; rozmiar każdego pliku przed zaszyfrowaniem nie może przekroczyć 100 MB (100 000 000 bajtów), a łączny rozmiar paczki ZIP - 5 GB (5 000 000 000 bajtów).</li></ul><h2 id="poprawne-szyfrowanie" tabindex="-1">Poprawne szyfrowanie <a class="header-anchor" href="#poprawne-szyfrowanie" aria-label="Permalink to &quot;Poprawne szyfrowanie&quot;">​</a></h2><ul><li>Faktura powinna być zaszyfrowana algorytmem AES-256-CBC (klucz symetryczny 256 bit, IV 128 bit, z dopełnieniem (padding) PKCS#7).</li><li>Klucz symetryczny szyfrowany algorytmem RSAES-OAEP (SHA-256/MGF1).</li></ul><h2 id="zgodnosc-metadanych-faktury-w-sesji-interaktywnej" tabindex="-1">Zgodność metadanych faktury w sesji interaktywnej <a class="header-anchor" href="#zgodnosc-metadanych-faktury-w-sesji-interaktywnej" aria-label="Permalink to &quot;Zgodność metadanych faktury w sesji interaktywnej&quot;">​</a></h2><ul><li>Obliczenie i weryfikacja skrótu faktury wraz z rozmiarem pliku.</li><li>Obliczenie i weryfikacja skrótu zaszyfrowanej faktury wraz z rozmiarem pliku.</li></ul><h2 id="ograniczenia-dotyczace-załacznikow" tabindex="-1">Ograniczenia dotyczące załączników <a class="header-anchor" href="#ograniczenia-dotyczace-załacznikow" aria-label="Permalink to &quot;Ograniczenia dotyczące załączników&quot;">​</a></h2><ul><li>Wysyłka faktur z załącznikami jest dozwolona tylko w trybie wsadowym.<br><strong>Wyjątek:</strong> W przypadku przesyłania <a href="./../offline/korekta-techniczna.html">korekty technicznej faktury offline</a> dopuszczalne jest użycie sesji interaktywnej.</li><li>Możliwość wysyłki faktur z załącznikami wymaga uprzedniego zgłoszenia tej opcji w usłudze <code>e-Urząd Skarbowy</code>.</li></ul><h2 id="wymagania-dotyczace-uprawnien" tabindex="-1">Wymagania dotyczące uprawnień <a class="header-anchor" href="#wymagania-dotyczace-uprawnien" aria-label="Permalink to &quot;Wymagania dotyczące uprawnień&quot;">​</a></h2><p>Wysłanie faktury do KSeF wymaga posiadania odpowiednich uprawnień do jej wystawienia w kontekście danego podmiotu.</p><p>* <strong>Uwaga:</strong> Jeżeli w scenariuszach biznesowych organizacji dostępne <a href="./../limity/limity.html">limity</a> są niewystarczające, prosimy o kontakt z działem wsparcia KSeF w celu przeprowadzenia indywidualnej analizy i doboru odpowiedniego rozwiązania.</p>',26)])])}const s=e(n,[["render",t]]);export{z as __pageData,s as default};
